# ─── Helpers ──────────────────────────────────────────────────────────────────


def get_artifact_type_definition(
    artifact_type: ArtifactType,
) -> ArtifactTypeRegistryEntry | None:
    """Returns the registry entry for the given artifact type, or None."""
    return next((e for e in ARTIFACT_TYPE_REGISTRY if e.type == artifact_type), None)


def get_persisted_artifact_types() -> list[ArtifactTypeRegistryEntry]:
    """Returns all artifact types that are persisted to durable storage."""
    return [e for e in ARTIFACT_TYPE_REGISTRY if e.persisted]


def should_persist_artifact(
    artifact_type: ArtifactType, backend: ArtifactStorageBackend
) -> bool:
    """Returns whether the given artifact should be persisted based on its type
    and the configured storage backend."""
    if backend == ArtifactStorageBackend.disabled:
        return False
    entry = get_artifact_type_definition(artifact_type)
    return entry.persisted if entry is not None else False
